final:
module gray_code_counter_2bit (
    input clk,
    input rst,
    output reg [1:0] gray
);

reg [1:0] binary;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
    if (rst) begin
        binary <= 2'b00;
    end else begin
        binary <= binary + 1;
    end
end

always @(binary) begin
    gray = binary ^ (binary >> 1);
end

endmodule
